VALUES
  ('police-b20a8cf8-moex-00034', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依憲法增修條文規定，關於總統解散立法院，下列敘述何者正確？', '["總統上任後，如所屬政黨在國會席次未過半，可藉由主動解散立法院改選立委，尋求最新 民意的支持", "立法院解散後應於60日內舉行立法委員選舉，並於選舉結果確認後10日內自行集會", "為即時因應政治困局，縱使於戒嚴或緊急命令生效期間，總統亦可解散立法院", "總統宣告解散立法院前應向司法院院長進行諮詢，以確保此一解散決定的合憲性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00035', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院釋字第613號解釋，有關獨立機關，下列敘述何者錯誤？', '["憲法規定行政院為國家最高行政機關，基於行政一體原則，須為包括獨立機關在內之所有 行政院所屬機關之整體施政表現負責", "獨立機關可以依據法律，排除上級機關於層級式行政體制下，對具體個案決定之指揮與監 督，不受政治干擾、可專業自主決定", "基於責任政治以及行政一體原則，行政院院長遇有更迭時，獨立機關之委員也應該與行政 院院長一同辭職，以符合民主正當性", "獨立機關之人選與其施政良窳有密切關係，故行政院應擁有對獨立機關重要人事一定之決 定權限，以落實行政一體及責任政治 51250、51350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00036', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依憲法增修條文規定，關於立法院立法委員之選舉，下列敘述何者錯誤？', '["任期4年，連選得連任", "由地區直轄市、縣市選舉出 73 人，依各其人口比例分配，並按應選名額劃分同額選舉區 選出之", "全國不分區及僑居國外國民共34人，依政黨名單投票選舉之，由獲得5%以上政黨選舉票 之政黨依得票比率選出之", "各政黨當選名單中，婦女不得低於三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00037', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '關於司法權，下列敘述何者錯誤？', '["司法院院長及副院長就預算案之審議，無需赴立法院備詢", "關於司法院所提出年度司法概算，行政院得加註意見後，編入中央政府總預算，送立法院 審議", "由大法官組成之憲法法庭，其審理範圍包含法規範憲法審查及裁判憲法審查案件", "本於司法行政監督權，最高司法機關就審理事項所發布之規則，涉及審判上之法律見解者， 法官於審判案件時，受其拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00038', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依憲法第63條規定，關於立法院之職權，不包括下列何者？', '["宣戰案", "戒嚴案", "特赦案", "大赦案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00039', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院釋字第738號解釋，下列敘述何者錯誤？', '["自治法規除不得違反中央與地方權限劃分外，若涉人民基本權之限制，仍應符合憲法第23 條之法律保留原則", "地方就其自治事項，或依法律及上級法規之授權，於合理範圍內以自治條例限制居民基本 權，不違法律保留原則", "轄區內電子遊戲場業營業場所距離之限制，係屬地方自治之範疇，地方自得訂定比中央法 律規定更為嚴格之要求", "轄區內電子遊戲場業營業場所之距離限制屬自治事項，不受法律拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00040', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '關於地方自治或中央與地方權限之規定，下列敘述何者錯誤？', '["屬於縣之立法權，由縣議會行之", "憲法並未明文規定直轄市有何自治事項", "中央法律宜留給地方，就其自治事項，有一定之立法或執行空間", "為貫徹地方自治，憲法較偏好地方分權，俾利因地制宜妥善處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00041', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', 'Officers obtain a legal from the court, allowing them to search the suspect’s home for evidencerelatedtotheburglary.', '["complaint", "warrant", "dispatcher", "baton"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00042', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', 'Policeinitiatedacovert operationbyplacinghiddencamerasaroundasuspect’sresidence togatherevidenceonpossiblecriminalactivity.', '["pursuit", "apprehend", "surveillance", "complaint"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00043', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', 'Thewomanofficiallyfileda againstherpartner,accusinghimofdomesticviolenceand requestingimmediateprotectionfromlocalauthorities.', '["affidavit", "custodyorder", "complaint", "subpoena"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
